// Output: "TypeError: Cannot read properties of undefined (reading 'name')"

let name = 'John Doe';
let greeting = 'Hello';
console.log(`${greeting}, ${name}!`); // Output: "Hello, John Doe!"

// A cleaner way to handle this:
function greet(user) {
   if (!user ||!user.name) {
     return 'Hello, Guest!';
   }
   return `Hello, ${user.name}!`;
}
console.log(greet({ name: 'Jane Doe' })); // Output: "Hello, Jane Doe!"

// Outputs: TypeError

A more elegant solution would be:

function greet(user = { name: 'Guest' }) {
   return `Hi, ${user.name.toUpperCase()}`;
}
console.log(greet()); // Outputs: Hi GUEST

This approach ensures we have a default value for user, reducing potential errors.
